        .app-wrapper {
            max-width: 1100px;
            margin: 0 auto;
            display: flex;
            flex-direction: column;
            gap: 28px;
        }

        /* ── Input Area ── */
        .input-area {
            display: flex;
            gap: 12px;
            align-items: center;
