        #add-card:hover {
            background: #4a7de0;
            box-shadow: 0 2px 8px rgba(91, 141, 239, 0.3);
        }

        #add-card:active {
            transform: scale(0.97);
        }

        /* ── Board ── */
        .board {
            display: flex;
            gap: 20px;
            align-items: flex-start;
        }

        /* ── Columns ── */
        .column {
            flex: 1;
            min-width: 0;
            background: #fff;
            border-radius: 12px;
            box-shadow: 0 1px 6px rgba(0, 0, 0, 0.06);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            transition: box-shadow 0.25s, outline 0.25s;
            outline: 3px solid transparent;
            outline-offset: -1px;
        }

        .column.drag-over {
            outline-color: #5b8def;
            box-shadow: 0 4px 20px rgba(91, 141, 239, 0.2);
            background: #f8faff;
        }

        .column-header {
            padding: 16px 18px 12px;
            font-weight: 700;
            font-size: 1rem;
            display: flex;
            align-items: center;
            gap: 8px;
            border-bottom: 1px solid #f0f2f5;
            letter-spacing: 0.01em;
        }

        .column-header .count {
            display: inline-flex;
            align-items: center;
            justify-content: center;
            background: #eef1f5;
            color: #555;
            font-size: 0.8rem;
            font-weight: 700;
            min-width: 24px;
            height: 24px;
            border-radius: 12px;
            padding: 0 7px;
            transition: background 0.2s, color 0.2s;
